// ── Booking income rules ─────────────────────────────────────────────────────
// Completed  → 100% of price
// Reserved   → price − balance (amount paid so far)
// Inquiry    → price − balance (amount paid so far)
// Cancelled  → 0
function bookingIncome(b) {
  const price   = +b.price   || 0;
  const balance = +b.balance || 0;
  if (b.status === "Completed") return price;
  if (b.status === "Reserved" || b.status === "Inquiry") return Math.max(0, price - balance);
  return 0; // Cancelled or anything else
}

function formatDT(dt) {
  const d = new Date(dt);
  return d.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) + " " +
         d.toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"});
}

